TDRecordBuilder = class("TDRecordBuilder", MaxRecordBuilder)

function TDRecordBuilder:ctor()

end

function TDRecordBuilder:getRecordStart(key, list, endCallback)
    local userIds = {}
    for _, record in pairs(list) do
        local value = record[1]
        for _, userId in pairs(StringUtil.split(value, "#")) do
            table.insert(userIds, tonumber(userId))
        end
    end
    UserInfoCache:GetCacheByUserIds(userIds, function()
        endCallback()
    end)
end

function TDRecordBuilder:buildValue(key, value)
    local userIds = StringUtil.split(value, "#")
    local backValue = ""
    for index, userId in pairs(userIds) do
        local userInfo = UserInfoCache:GetCache(tonumber(userId)) or { name = "" }
        backValue = backValue .. userInfo.name .. "," .. userId
        if index < #userIds then
            backValue = backValue .. "#"
        end
    end
    return backValue
end
